import { createContext, useContext, useContextSelector } from 'use-context-selector';
import { createContextHook } from '@universe-design/react-utilities';
import type { useFile } from './useFile';

export type FileContextType = ReturnType<typeof useFile>;
export const {
  Provider: FileContextProvider,
  useContext: useFileContext,
  useContextSelector: useFileContextSelector,
} = createContextHook<FileContextType>('FileContext', {
  strict: true,
  customizedContextMethods: {
    createContext,
    useContext,
    useContextSelector,
  },
});
